  assign in2_inv = _GEN;
  wire [63:0] _in1_xor_in2 = io_in1 ^ _GEN;
  assign in1_xor_in2 = _in1_xor_in2;
  wire [63:0] _GEN_0 = io_in1 + _GEN + {63'h0, io_fn[3]};
